VALUES
  ('real-estate-moex-02212', 'real-estate', 'real-estate-moex-099-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '公平交易法規定事業不得為聯合行為，但有益於整體經濟與公共利益，並經中央主管機關許可者，可不 受此一限制。下列何者不為前述得不受限制之情形：', '["為降低成本、改良品質或增進效率，但不統一商品規格或型式者", "為促進事業合理經營，而分別做專業發展者", "為加強貿易效能，而就國外商品之輸入採取共同行為者", "為確保或促進輸出，而專就國外市場之競爭予以約定者"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:11+00:00", "source_pdf_sha1": "fd1783d600a7", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 10, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02213', 'real-estate', 'real-estate-moex-099-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '下列之說明，何者為正確？', '["公平交易委員會依公平交易法為調查時，得通知有關機關或個人提出帳冊等證物", "未經認許之外國法人或團體，就公平交易法規定事項不得為告訴、自訴或提起民事訴訟", "多層次傳銷事業，係指就多層次傳銷訂定授權計畫或組織，統籌規劃傳銷行為之事業", "當事人或關係人於公平交易委員會調查程序進行中，得申請抄閱有關行政決定前之擬稿"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:11+00:00", "source_pdf_sha1": "fd1783d600a7", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 11, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02214', 'real-estate', 'real-estate-moex-099-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '有關公平交易法第21條之規定，下列何者錯誤？', '["事業不得在商品上對於商品之製造方法為虛偽不實表示", "事業對在商品廣告上對於商品之用途為引人錯誤之表示時，此商品不得運送", "事業不得以其他使公眾得知之方法，對於商品之使用方法為虛偽不實之表示", "廣告媒體業知曉其刊載之廣告有引人錯誤之虞，仍予刊載，損害賠償責任在廣告主，其無須負連帶損 害賠償責任"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:11+00:00", "source_pdf_sha1": "fd1783d600a7", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 12, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02215', 'real-estate', 'real-estate-moex-099-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '下列何者不屬於行政院公平交易委員會之職掌：', '["事業活動及經濟情況之調查", "擬訂公平交易政策及法規", "違反公平交易法之調查與處分", "事業結合時，公告參與結合之事業其銷售金額之標準"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:11+00:00", "source_pdf_sha1": "fd1783d600a7", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 13, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02216', 'real-estate', 'real-estate-moex-099-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '法院對事業違反公平交易法之規定，致侵害他人權益時，對被害人之請求，如為事業之故意行為，得依 侵害情節，酌定損害額以上之賠償，但不得超過已證明損害額之幾倍？', '["2倍", "3倍", "4倍", "5倍"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:11+00:00", "source_pdf_sha1": "fd1783d600a7", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 14, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02217', 'real-estate', 'real-estate-moex-099-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '依消費者保護法之規定，定型化契約條款如有疑義時，應為有利於何人之解釋？', '["企業經營者", "政府", "消費者", "消費者保護團體"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:11+00:00", "source_pdf_sha1": "fd1783d600a7", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 15, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02218', 'real-estate', 'real-estate-moex-099-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '下列有關公寓大廈營運與管理維護之敘述，何者錯誤？', '["公寓大廈管理員以受僱人身分簽名或蓋章代收稅單即生送達效力", "管理服務人得同時受聘於二家以上之管理維護公司", "公寓大廈利害關係人於必要時，得請求閱覽或影印會計憑證", "管理委員之選任事項，不得以臨時動議提出"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:11+00:00", "source_pdf_sha1": "fd1783d600a7", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 16, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02219', 'real-estate', 'real-estate-moex-099-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '企業經營者與消費者訂立定型化契約前，如未能提供合理期間供消費者審閱全部條款內容時，下列何者 正確？', '["其條款無需經消費者之主張，仍構成契約之內容", "其條款不構成契約之內容，且消費者亦不得主張該條款構成契約之內容", "其條款不構成契約之內容，但消費者得主張該條款仍構成契約之內容", "其條款構成契約之內容，但消費者得主張該條款不構成契約之內容"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:11+00:00", "source_pdf_sha1": "fd1783d600a7", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 17, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02220', 'real-estate', 'real-estate-moex-099-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '依消費者保護法第12條之規定，定型化契約中之條款有下列那種情形時，不屬於推定其顯失公平之情形？', '["條款與其所排除不予適用之任意規定之立法意旨顯相矛盾者", "條款之全部或一部無效或不構成契約內容之一部者", "契約之主要權利或義務，因受條款之限制，致契約之目的難以達成者", "違反平等互惠原則者"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:11+00:00", "source_pdf_sha1": "fd1783d600a7", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 18, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02221', 'real-estate', 'real-estate-moex-099-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '定型化契約中之定型化契約條款牴觸個別磋商條款之約定時，下列何者正確？', '["定型化契約中之定型化契約條款牴觸個別磋商條款部分無效", "個別磋商條款牴觸定型化契約中之定型化契約條款部分無效", "定型化契約中之定型化契約條款牴觸個別磋商條款時，兩者皆無效", "定型化契約中之定型化契約條款牴觸個別磋商條款時，兩者皆有效，以有利消費者之條款為主"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:11+00:00", "source_pdf_sha1": "fd1783d600a7", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 19, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
